import torch
import torch.distributed as dist
import torch.nn.functional as F


class _AllGatherLastDim(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_, world_size):
        ctx.world_size = world_size
        if world_size == 1:
            return input_

        gathered = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(gathered, input_.contiguous())
        return torch.cat(gathered, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        if ctx.world_size == 1:
            return grad_output, None

        rank = dist.get_rank()
        return grad_output.chunk(ctx.world_size, dim=-1)[rank].contiguous(), None


class _AllReduceSum(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_, world_size):
        ctx.world_size = world_size
        if world_size == 1:
            return input_

        output = input_.clone()
        dist.all_reduce(output, op=dist.ReduceOp.SUM)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        if ctx.world_size == 1:
            return grad_output, None

        grad_input = grad_output.clone()
        dist.all_reduce(grad_input, op=dist.ReduceOp.SUM)
        return grad_input, None


def _get_world_size():
    return dist.get_world_size() if dist.is_available() and dist.is_initialized() else 1


def _get_rank():
    return dist.get_rank() if dist.is_available() and dist.is_initialized() else 0


def _partition_bounds(size, world_size, rank):
    if size % world_size != 0:
        raise ValueError(f"feature dimension {size} must be divisible by world_size {world_size}")

    per_partition = size // world_size
    start = rank * per_partition
    end = start + per_partition
    return start, end


class ColumnParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.world_size = _get_world_size()
        self.rank = _get_rank()

        if tuple(master_weight.shape) != (out_features, in_features):
            raise ValueError(
                f"master_weight must have shape {(out_features, in_features)}, "
                f"got {tuple(master_weight.shape)}"
            )

        start, end = _partition_bounds(out_features, self.world_size, self.rank)
        self.output_start = start
        self.output_end = end
        self.out_features_per_partition = end - start

        self.weight = torch.nn.Parameter(master_weight[start:end].detach().clone())
        if bias:
            self.bias = torch.nn.Parameter(master_weight.new_zeros(self.out_features_per_partition))
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight, self.bias)
        return _AllGatherLastDim.apply(local_output, self.world_size)


class RowParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.world_size = _get_world_size()
        self.rank = _get_rank()

        if tuple(master_weight.shape) != (out_features, in_features):
            raise ValueError(
                f"master_weight must have shape {(out_features, in_features)}, "
                f"got {tuple(master_weight.shape)}"
            )

        start, end = _partition_bounds(in_features, self.world_size, self.rank)
        self.input_start = start
        self.input_end = end
        self.in_features_per_partition = end - start

        self.weight = torch.nn.Parameter(master_weight[:, start:end].detach().clone())
        if bias:
            self.bias = torch.nn.Parameter(master_weight.new_zeros(out_features))
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        input_parallel = input_[..., self.input_start:self.input_end]
        local_output = F.linear(input_parallel, self.weight, None)
        output = _AllReduceSum.apply(local_output, self.world_size)
        if self.bias is not None:
            output = output + self.bias
        return output

